import pytest

MAX_TITLE_LEN = 255

def test_create_document_title_at_maximum_length_boundary(
    admin_session,
    api_base_url,
    cleanup_document,
):
    title_at_max = "T" * MAX_TITLE_LEN
    resp_ok = admin_session.post(
        f"{api_base_url}/documents",
        json={"title": title_at_max, "type": "policy", "content": "c", "owner": "admin"}
    )
    assert resp_ok.status_code in (200, 201), (
        f"255-char title should succeed; got {resp_ok.status_code}"
    )
    entity_id = (resp_ok.json().get("id") or resp_ok.json().get("documentId"))
    assert entity_id, "Entity id must be present for valid creation"
    cleanup_document(entity_id)

    title_over_max = "T" * (MAX_TITLE_LEN + 1)
    resp_bad = admin_session.post(
        f"{api_base_url}/documents",
        json={"title": title_over_max, "type": "policy", "content": "c", "owner": "admin"}
    )
    assert resp_bad.status_code == 400, (
        f"256-char title should fail with 400; got {resp_bad.status_code}"
    )
